class PersonBad {
    public String name;
    public int age;  // dangerous — anyone can set age = -99
}

class PersonGood {
    private String name;    // hidden — only accessible via methods
    private int age;

    PersonGood(String name, int age) {
        this.name = name;
        setAge(age);  // validate even in constructor
    }

    void setAge(int age) {
        if (age < 0 || age > 150) throw new IllegalArgumentException("Invalid age: " + age);
        this.age = age;
    }

    int getAge()    { return age; }
    String getName(){ return name; }
}

public class Main {
    public static void main(String[] args) {
        PersonBad bad = new PersonBad();
        bad.age = -99;  // Java allows this — very wrong!
        System.out.println("Bad age: " + bad.age);

        PersonGood good = new PersonGood("Alex", 25);
        System.out.println("Good age: " + good.getAge());

        try {
            good.setAge(-1);  // throws!
        } catch (IllegalArgumentException e) {
            System.out.println("Caught: " + e.getMessage());
        }
    }
}

class Counter {
    private int count;        // private field
    private int maxCount;     // private field

    public Counter(int maxCount) {  // public constructor
        this.count = 0;
        this.maxCount = maxCount;
    }

    public void increment() {       // public method
        if (count < maxCount) count++;
    }

    public void decrement() {       // public method
        if (count > 0) count--;
    }

    public int getCount() {         // public getter
        return count;
    }

    public boolean isFull() {       // public derived value
        return count == maxCount;
    }
}

public class Main {
    public static void main(String[] args) {
        Counter c = new Counter(3);
        c.increment();
        c.increment();
        c.increment();
        c.increment();  // no effect — at max
        System.out.println(c.getCount());
        System.out.println(c.isFull());
    }
}

class User {
    private String name;
    private String email;

    public User(String name, String email) {
        this.name = name;
        setEmail(email);  // validate on construction
    }

    public String getName()  { return name; }
    public String getEmail() { return email; }

    // TODO: add setEmail(String email) that validates '@' is present
    public void setEmail(String email) {
        if (!email.contains("@")) {
            throw new IllegalArgumentException("Invalid email: " + email);
        }
        this.email = email;
    }
}

public class Main {
    public static void main(String[] args) {
        User u = new User("Alex", "alex@example.com");
        System.out.println(u.getName() + " — " + u.getEmail());

        try {
            u.setEmail("not-an-email");
        } catch (IllegalArgumentException e) {
            System.out.println("Error: " + e.getMessage());
        }
    }
}

final class Money {
    private final double amount;
    private final String currency;

    public Money(double amount, String currency) {
        if (amount < 0) throw new IllegalArgumentException("Amount cannot be negative");
        this.amount = amount;
        this.currency = currency;
    }

    public double getAmount()   { return amount; }
    public String getCurrency() { return currency; }

    // Returns a NEW Money object — doesn't modify this one!
    public Money add(Money other) {
        if (!currency.equals(other.currency)) throw new IllegalArgumentException("Currency mismatch");
        return new Money(this.amount + other.amount, currency);
    }

    @Override
    public String toString() {
        return String.format("%.2f %s", amount, currency);
    }
}

public class Main {
    public static void main(String[] args) {
        Money price = new Money(19.99, "USD");
        Money tax   = new Money(2.00, "USD");
        Money total = price.add(tax);

        System.out.println(price);
        System.out.println(tax);
        System.out.println(total);
        System.out.println(price); // unchanged!
    }
}

class Config {
    private final String host;
    private final int port;
    private final boolean ssl;
    private final int timeout;

    private Config(Builder builder) {
        this.host    = builder.host;
        this.port    = builder.port;
        this.ssl     = builder.ssl;
        this.timeout = builder.timeout;
    }

    @Override
    public String toString() {
        return String.format("Config{host=%s, port=%d, ssl=%b, timeout=%ds}", host, port, ssl, timeout);
    }

    static class Builder {
        private String host;
        private int port    = 80;
        private boolean ssl = false;
        private int timeout = 30;

        Builder(String host) { this.host = host; }

        Builder port(int port)       { this.port = port;    return this; }
        Builder ssl(boolean ssl)     { this.ssl  = ssl;     return this; }
        Builder timeout(int timeout) { this.timeout = timeout; return this; }

        Config build() { return new Config(this); }
    }
}

public class Main {
    public static void main(String[] args) {
        Config dev  = new Config.Builder("localhost").port(8080).build();
        Config prod = new Config.Builder("api.example.com").port(443).ssl(true).timeout(60).build();

        System.out.println(dev);
        System.out.println(prod);
    }
}
